issue_body:
Hello:
in my project, i have about one thousand urls source, i wrote a api to create project and pull them into database. now I want to start them, after checking your source code, there are two steps: 1 update the project status to "RUNNING",  2 Running the project. I wrote api which gets all projects from database which status is not running  and change their statuses to running,  then running them, the function running in my api is same as your function runtask of index.py in webui repo. But the my function just shows my a logger "[E 161124 10:33:02 scheduler:169] unknown project: test_123321123" , "test_123321123" is my project name. could you give me some suggestions? Thanks

below is my code:

function 1
```
def run_project_task(name):
    rpc = app.config['scheduler_rpc']
    if rpc is None:
        return {}
    projectdb = app.config['projectdb']
    project = name
    project_info = projectdb.get(project, fields=('name', 'group'))
    if not project_info:
        return 404, "no such project."

    newtask = {
        "project": project,
        "taskid": "on_start",
        "url": "data:,on_start",
        "process": {
            "callback": "on_start",
        },
        "schedule": {
            "age": 0,
            "priority": 9,
            "force_update": True,
        },
    }

    try:
        ret = rpc.newtask(newtask)
    except socket.error as e:
        app.logger.warning('connect to scheduler rpc error: %r', str(e))
        return 500, False
    else:
        return 200, ret
```

function 2
```
def change_project_status(name, status="RUNNING"):
    """
    用来将所有的项目的状态全部改成running
    Handler: Albert_Chen
    :param name:
    :param status:
    :return:
    """
    projectdb = app.config['projectdb']
    update = {"status": status}
    ret = projectdb.update(name, update)
    if ret:
        rpc = app.config['scheduler_rpc']
        if rpc is not None:
            try:
                rpc.update_project()
            except socket.error as e:
                app.logger.warning('connect to scheduler rpc error: %r', e)
                return 200, "rpc error"
        return 200, 'ok'
    else:
        return 500, 'error'
```

My api

```
@app.route('/api/start/all', methods=["GET"])
def api_projects_start_all():
    projectdb = app.config['projectdb']
    projects = projectdb.get_many({"status": {"$ne":"RUNNING"}})
    for project in projects:
        project_name = project.get('name', '')

        if project_name:
            code, msg = change_project_status(project_name)
            if code == 200:
                app.logger.info('Change %s successful' %project_name)
                code, msg = run_project_task(project_name)
                if code == 200:
                    app.logger.info('Start %s successful'%project_name)
                else:
                    app.logger.info('Start %s failed' %project_name)
            else:
                app.logger.warning('Change %s failed' %project_name)
    return json.dumps({"code_status": 200, "msg":'ok'})
```

