Hi,

I need to upload campaigns in my work using the AdWords API and I am facing with an problem related to the Error Handling. I developed my tool by starting from the examples I found in the googleads (Python) github. The problem is that, when I try to mutate a bunch of operations (2000 or less, as the documentation says) using the validate_only method, sometimes, one or more errors are not raised and then I don't solve/remove these problematic operations. When I solve the raised operations and try to perform a mutate now without the validate_only method, it raises an error.

I think it is caused by a bug in the library or by something that I am passing over. With the aim of showing you where the error is happening, I wrote a easily reproducible example where I try to mutate an "illegal" operation 10000 times. I found that about 1 out of 10000 times the operation is not marked as "illegal" and it makes me think that something bad happens. 

I am using the last version of the googleads library with Python 2.7 installed from the Anaconda Environment.

```
adgroup_id = # The Adgroup Id of an existing Adgroup
client = # Your client object

keyword = "test protos"
operations= []

op = {
'xsi_type': 'BiddableAdGroupCriterion',
'adGroupId': adgroup_id,
'biddingStrategyConfiguration': {
    'bids': [{
            'xsi_type': 'CpcBid',
            'bid': {
                'microAmount': '300000'},
        }
    ]
},
'criterion': {
    'xsi_type': 'Keyword',
    'matchType': 'BROAD',
    'text': keyword
}
}

operations.append({
'operator': 'ADD',
'operand': op
})

number_of_errors=[]
ERRORS=[]
ad_group_criterion_service = _client.GetService('AdGroupCriterionService', version='v201509')

# Let's try to repeat the same operation a lot of times
client.validate_only = True
for i in range(10000):
    errors=[]
    try:
        ad_group_criterion_service.mutate(operations)
    except suds.WebFault, e:
        errors = e.fault.detail.ApiExceptionFault.errors if type(
            e.fault.detail.ApiExceptionFault.errors) == list else [e.fault.detail.ApiExceptionFault.errors]
    number_of_errors.append(len(errors))
    ERRORS.append(e)
```

Hello, I have got some settings running on 2 servers, they are both identical apart from one running 4.0.5 and the other one running 4.0.6 of exabgp.

Now the issue I am having is related to my log collector, the files are exactly the same for both versions:
The only difference is that version 4.0.5 gets a pprint which is a normal format for tag rd, as followed: "rd": "XXXXX:XXXXX"
The 4.0.6 gets a pprint which is as followd : "rd":  "?\xfd\x91\x00\x00\xfd\xfa\x00".
This stops my exabgp session and I can't log the files.

Script I'm using is as followed:


```

#!/usr/bin/env python
import sys
import socket
import json
from pprint import pprint

sock = socket.socket()
sock.connect( ('IP', 5150) )

def get_attrs(json_in):
    attrs = {}
    attrs['neighbor'] =     json_in['neighbor']['address']['peer']
    attrs['peeras'] =       json_in['neighbor']['asn']['peer']

    msgtype =               json_in['neighbor']['message'].keys()[0]
    attrs['msgtype'] = msgtype

    if 'announce' in        json_in['neighbor']['message'][msgtype].keys():
      action = 'announce'
    elif 'withdraw' in      json_in['neighbor']['message'][msgtype].keys():
      action = 'withdraw'
    else:
      print "funky action in this message, %s" % json_in
    attrs['action'] = action

    afisafi  =              json_in['neighbor']['message'][msgtype][action].keys()[0]
    attrs['afi'] = afisafi.split()[0]
    attrs['safi'] = afisafi.split()[1]

    if action == 'announce':
      nexthop =             json_in['neighbor']['message'][msgtype][action][afisafi].keys()[0]
      attrs['nexthop'] =      nexthop

      # simple mapping, but substitute hyphens since elastic doesn't like em
      simple_attributes = ['local-preference','origin','med','originator-id','cluster-list']
      for simple_attribute in simple_attributes:
        if json_in['neighbor']['message'][msgtype]['attribute'].has_key(simple_attribute):
          attrs[simple_attribute.replace('-','')] = json_in['neighbor']['message'][msgtype]['attribute'][simple_attribute]

      # as-path needs to be casted from list to string
      if json_in['neighbor']['message'][msgtype]['attribute'].has_key('as-path'):
        if type(json_in['neighbor']['message'][msgtype]['attribute']['as-path']) == type([]):
          attrs['aspath'] = ' '.join(str(x) for x in json_in['neighbor']['message'][msgtype]['attribute']['as-path'])
        else:
          attrs['aspath'] =   json_in['neighbor']['message'][msgtype]['attribute']['as-path']

      # ext comms are string/value pairs by exa, only keep strings
      if json_in['neighbor']['message'][msgtype]['attribute'].has_key('extended-community'):
        extcomms = []
        for extcomm in json_in['neighbor']['message'][msgtype]['attribute']['extended-community']:
          extcomms.append(extcomm['string'])
        attrs['extcomms'] = extcomms

      # regular comms are lists, rewrite to colon=separated
      if json_in['neighbor']['message'][msgtype]['attribute'].has_key('community'):
        comms = []
        for comm in json_in['neighbor']['message'][msgtype]['attribute']['community']:
          comms.append("%s:%s" % (comm[0],comm[1]))
        attrs['community'] = comms
    return attrs


def get_evpn_routes(announce_in):
    announce = {}
    announce['rd'] =           announce_in['rd']
    routetype =                announce_in['code']
    routetypename =            announce_in['name']
    announce['routetype'] =    routetype
    announce['routetypename'] =    routetypename
    if routetype == 1:
      announce['esi'] = announce_in['esi']
      announce['ethernettag'] = announce_in['ethernet-tag']
      announce['label'] = announce_in['label']
    elif routetype == 2:
      announce['esi'] = announce_in['esi']
      announce['mac'] = announce_in['mac']
      announce['ethernettag'] = announce_in['ethernet-tag']
      try:
        announce['ip'] = announce_in['ip']
      except KeyError:
        pass
      announce['label'] = announce_in['label']
    elif routetype == 3:
      announce['ethernettag'] = announce_in['ethernet-tag']
      announce['ip'] = announce_in['ip']
    elif routetype == 4:
      announce['ip'] = announce_in['ip']
      announce['esi'] = announce_in['esi']
    elif routetype == 5:
      pass
    else: # not supported
      pass
    return announce

def get_mpls_vpn_routes(announce_in):
    announce = {}
    announce['rd'] =           announce_in['rd']
    announce['label'] = announce_in['label']
    announce['prefix'] = announce_in['nlri']

    return announce

def get_unicast_routes(announce_in):
